/* SHIELD — reels.js (이미지 내장 버전) */

var REEL_IMAGES = {
  hotperm: "data:image/png;base64,",
  coldperm: "data:image/png;base64,",
  color: "data:image/png;base64,",
  clinic: "data:image/jpeg;base64,",
  growth: "data:image/png;base64,",
  smell: "data:image/png;base64,",
  ingredient: "data:image/png;base64,",
  bleach: "data:image/jpeg;base64,",
  neutralize: "data:image/jpeg;base64,",
};

/* 콘텐츠 데이터 - 새 영상 추가 시 여기에만 추가 */
var REELS_DATA = [
  { title:"열펌",      desc:"열펌을 하면 머리카락 속에서 어떤 일이 일어날까요?",   link:"https://www.instagram.com/reel/DVll-u7jypR/", img: REEL_IMAGES.hotperm },
  { title:"일반펌",    desc:"일반펌을 하면 머리카락 속에서 어떤 일이 일어날까요?", link:"https://www.instagram.com/reel/DVL1O7DDz5p/", img: REEL_IMAGES.coldperm },
  { title:"염색",      desc:"염색을 하면 머리카락 속에서 어떤 일이 일어날까요?",   link:"https://www.instagram.com/reel/DU8VI0_D6ke/", img: REEL_IMAGES.color },
  { title:"크리닉",    desc:"크리닉을 하면 머리카락 속에서 어떤 일이 일어날까요?", link:"https://www.instagram.com/reel/DWOI9jIj-yj/", img: REEL_IMAGES.clinic },
  { title:"머리카락 성장", desc:"머리카락은 어떻게 자라날까요?",                   link:"https://www.instagram.com/reel/DWGRKGmj54p/", img: REEL_IMAGES.growth },
  { title:"냄새",      desc:"미용실 특유의 냄새는 무엇일까요?",                    link:"https://www.instagram.com/reel/DV_E96ej0N-/", img: REEL_IMAGES.smell },
  { title:"성분",      desc:"염색약에는 어떤 성분이 들어있을까요?",                link:"https://www.instagram.com/reel/DVxzDZcD2bz/", img: REEL_IMAGES.ingredient },
  { title:"탈색",      desc:"탈색을 하면 머리카락 속에서 어떤 일이 일어날까요?",   link:"https://www.instagram.com/reel/DVr9ljaD165/", img: REEL_IMAGES.bleach },
  { title:"보색중화",  desc:"보색중화를 하면 머리카락 속에서 어떤 일이 일어날까요?",link:"https://www.instagram.com/reel/DVSWamFDyJE/", img: REEL_IMAGES.neutralize },
];

function renderReels() {
  var grid = document.getElementById('reels-grid');
  if (!grid) return;
  grid.innerHTML = '';
  REELS_DATA.forEach(function(item, i) {
    var card = document.createElement('a');
    card.className = 'reel-card';
    card.href = item.link;
    card.target = '_blank';
    card.rel = 'noopener noreferrer';
    card.style.animationDelay = Math.min(i * 0.06, 0.4) + 's';
    card.innerHTML =
      '<div class="reel-thumb-wrap">' +
        '<img class="reel-thumb" src="' + item.img + '" alt="' + item.title + '" />' +
        '<div class="reel-play-btn"><svg viewBox="0 0 24 24" fill="white" width="28" height="28"><polygon points="5,3 19,12 5,21"/></svg></div>' +
      '</div>' +
      '<div class="reel-info">' +
        '<div class="reel-title">' + item.title + '</div>' +
        '<div class="reel-desc">' + item.desc + '</div>' +
        '<div class="reel-cta">Instagram Reels 보기 →</div>' +
      '</div>';
    grid.appendChild(card);
  });
}
